import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable Deepviews","description":"","frontmatter":{"title":"Enable Deepviews","slug":"enable-deepviews"},"headers":[],"relativePath":"marketer-hub/enable-deepviews.md","filePath":"marketer-hub/enable-deepviews.md"}'),r={name:"marketer-hub/enable-deepviews.md"};function n(s,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><h3 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h3><p>In order to enable Deepviews, you require <a href="./add-manage-users-roles-permissions-access.html">specific permissions</a> to your Branch app:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Description</th><th>Access</th></tr></thead><tbody><tr><td>App-Level Settings</td><td>Settings or features that can impact functionality app-wide.</td><td>Edit or Admin Access Level</td></tr></tbody></table><h2 id="_1-navigate-to-the-deepviews-tab" tabindex="-1">1. Navigate to the Deepviews tab <a class="header-anchor" href="#_1-navigate-to-the-deepviews-tab" aria-label="Permalink to &quot;1. Navigate to the Deepviews tab&quot;">​</a></h2><p>Log into Branc . From the <strong>Configuration</strong> page, navigate to the <a href="https://dashboard.branch.io/configuration/deepview-manager" target="_blank" rel="noreferrer">Deepview Manager tab</a>.</p><h2 id="_2-enable-deepviews" tabindex="-1">2. Enable Deepviews <a class="header-anchor" href="#_2-enable-deepviews" aria-label="Permalink to &quot;2. Enable Deepviews&quot;">​</a></h2><p>Branch will automatically generate several Deepviews for you based on what settings you have set in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration page</a>. Deepviews are configured separately for visitors on each platform: iOS, Android, Desktop. There&#39;s a tab for each platform and pre-built templates that you can customize. Review the templates, for the ones you want to customize toggle the <strong>Enable</strong> slider.</p><p>Branch offers several different templates for you to use, duplicate, and customize for your specific brand. The core layout of the pre-built templates allows you to showcase high-level information about your app. You have the following elements to configure:</p><ul><li>App Image</li><li>App Name</li><li>Deepview Title</li><li>Deepview Description</li><li>Call-to-Action Text</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>We recommend utilizing QR Codes as much as possible, and you can utilize Branch&#39;s Desktop QR Code Deepview to drive users to your app.</p></div><h2 id="_3-create-a-custom-deepview" tabindex="-1">3. Create a custom Deepview <a class="header-anchor" href="#_3-create-a-custom-deepview" aria-label="Permalink to &quot;3. Create a custom Deepview&quot;">​</a></h2><p>You can also create a Custom Deepview to be more specific with different attributes of the Deepview. There are 2 ways to create a custom template:</p><ul><li>Find a default template and click on the <code>...</code> and then click <strong>Duplicate</strong>.</li><li>Alternatively, scroll to the bottom of the Deepview page, and click <strong>+ New Deepview</strong>.</li></ul><p>Note: Unlike the prebuilt template, custom Deepview templates are shared between all platforms (iOS, Android, and desktop), and cannot be deleted after creation.</p><div class="warning custom-block"><p class="custom-block-title">Special Characters</p><p>Using special characters like <code>+</code> for the name/key of the Deepview will break the URL. Avoid using special characters.</p></div><p>There are several properties that you can edit the Deepview using the different tabs:</p><h3 id="basic" tabindex="-1">Basic <a class="header-anchor" href="#basic" aria-label="Permalink to &quot;Basic&quot;">​</a></h3><p>Displays your new template, and allows you to modify the default fallback OG tags used if none are specified for a link.</p><h3 id="html-and-css-editor" tabindex="-1">HTML and CSS Editor <a class="header-anchor" href="#html-and-css-editor" aria-label="Permalink to &quot;HTML and CSS Editor&quot;">​</a></h3><p>The <strong>Editor</strong> tab allows you to edit the raw HTML and CSS for your template. The rendered template will update as you modify the HTML and CSS.</p><p>Select <strong>Save</strong> when you are done editing your Deepview.</p><h2 id="using-your-deepviews" tabindex="-1">Using your Deepviews <a class="header-anchor" href="#using-your-deepviews" aria-label="Permalink to &quot;Using your Deepviews&quot;">​</a></h2><p>You can configure your Branch Links to use Deepviews when the user clicks on the link.</p><h4 id="short-links-redirects" tabindex="-1">Short Links redirects <a class="header-anchor" href="#short-links-redirects" aria-label="Permalink to &quot;Short Links redirects&quot;">​</a></h4><p>When creating a Branch <a href="./create-quick-links.html">Short Link</a>, you can set a specific Deepview to show when users click on links without the app installed. Simply select <strong>Deepview</strong> for the platform, and the enabled Deepview of your choice in the dropdown.</p><h4 id="branch-link-data" tabindex="-1">Branch Link data <a class="header-anchor" href="#branch-link-data" aria-label="Permalink to &quot;Branch Link data&quot;">​</a></h4><p>Additionally, you can show a Deepview by setting the redirect through the link data. Whatever mechanism you are using to create your <a href="./creating-a-deep-link.html">Branch Link</a>, you can add the following key/value pairs:</p><table tabindex="0"><thead><tr><th>Key</th><th>Usage</th><th>Example</th></tr></thead><tbody><tr><td><code>$ios_deepview</code></td><td>The key of the Deepview template to use for iOS.</td><td><code>branch_default</code></td></tr><tr><td><code>$android_deepview</code></td><td>The key of the Deepview template to use for Android.</td><td><code>branch_default</code></td></tr><tr><td><code>$desktop_deepview</code></td><td>The key of the Deepview template to use for the Desktop.</td><td><code>branch_qr_code_default</code></td></tr></tbody></table><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Can I change the app icon that appears in social media posts?</summary><p><strong>In Legacy Branch</strong></p><p>You can upload a new icon in the <strong>Social Media Preview</strong> of section on the <strong>Configuration</strong> <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">page</a>.</p><p>Please note that this feature is reserved for paid Branch accounts with a dedicated contract. If you do not have a paid Branch account, you will not see this feature in the Branch Dashboard.</p><p><strong>In New Branch</strong></p><p>You can upload a new icon by going to <strong>Configuration</strong> &gt; <strong>Link Controls</strong> &gt; <strong>Link Appearance</strong> &gt; <strong>Link Preview</strong>. Select <strong>Configure</strong> to change your icon.</p></details><details><summary>Can I edit a Deepview template?</summary><p>No, you cannot edit a template. However, you can duplicate a template, and then customize the template.</p></details><details><summary>Can I add Javascript to my custom Deepview template?</summary><p>No. Before rendering the template, we sanitize the markup of Javascript for security reasons. This includes script tags and event attributes on tags.</p></details><details><summary>Can I customize the favicon of the Deepview domain?</summary><p>On the Branch Dashboard, navigate to the <strong>Configuration</strong> section to Edit your <strong>Deepview</strong>.</p><p>In the <strong>Desktop DeepView Editor,</strong> include the below code snippet along with your image URL -</p><p><code>&lt;link rel=&quot;icon&quot; type=&quot;image/png&quot; href=&quot;https://example.com/favicon.png&quot; /&gt;</code></p><p>Save the changes and you should see your favicon now for Desktop Deepviews.</p></details>',34)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
